import {
  useCallback,
  useEffect,
  useRef,
  type MouseEvent as ReactMouseEvent,
} from 'react';

import * as headerCellStyles from '../components/DataTableHeaderCell.sty.js';
import { DATA_TABLE_NARROW_HEADER_THRESHOLDS } from '../constants.js';

interface UseHeaderCellInteractionsParams {
  headerCell: HTMLDivElement | null;
  canSort: boolean;
  canColumnActions: boolean;
  isActiveFloatingMenu: boolean;
  rowDensity: 'default' | 'condensed' | 'comfortable';
  getToggleSortingHandler: () => undefined | ((event: unknown) => void);
}

interface UseHeaderCellInteractionsResult {
  handleCellActionsClose: () => void;
  handleCellMouseEnter: () => void;
  handleCellMouseLeave: (
    event: ReactMouseEvent<HTMLDivElement, MouseEvent>,
  ) => void;
  handleCellClick: (event: ReactMouseEvent<HTMLDivElement, MouseEvent>) => void;
}

/**
 * Checks whether an element is interactive.
 */
function isInteractiveElement(element: HTMLElement | SVGElement): boolean {
  const interactiveTags = ['BUTTON', 'A', 'LABEL', 'INPUT', 'SELECT'];

  return !!(
    interactiveTags.includes(element.tagName) ||
    element.getAttribute('tabindex')
  );
}

export function useHeaderCellInteractions({
  headerCell,
  canSort,
  canColumnActions,
  isActiveFloatingMenu,
  rowDensity,
  getToggleSortingHandler,
}: UseHeaderCellInteractionsParams): UseHeaderCellInteractionsResult {
  const isHoveredRef = useRef(false);

  // When the floating menu opens for this header, React's re-render overwrites
  // element.className and drops the imperatively-managed `hovered` class. Restore it
  // so the sorting arrow stays visible while the cursor is still over the column.
  useEffect(() => {
    if (!isActiveFloatingMenu || !isHoveredRef.current || !headerCell) {
      return;
    }
    headerCell.classList.add(headerCellStyles.hovered);
  }, [isActiveFloatingMenu, headerCell]);

  const handleCellActionsClose = useCallback((): void => {
    if (headerCell) {
      isHoveredRef.current = false;
      // remove the hovered and narrow state
      headerCell.classList.remove(
        headerCellStyles.hovered,
        headerCellStyles.narrow,
      );
    }
  }, [headerCell]);

  const handleCellMouseEnter = useCallback((): void => {
    if (!headerCell || (!canColumnActions && !canSort)) {
      return;
    }

    isHoveredRef.current = true;
    headerCell.classList.add(headerCellStyles.hovered);

    const widthThreshold = DATA_TABLE_NARROW_HEADER_THRESHOLDS[rowDensity];
    if (!widthThreshold) {
      return;
    }

    const headerWidth = headerCell.getBoundingClientRect().width;
    if (headerWidth <= widthThreshold) {
      headerCell.classList.add(headerCellStyles.narrow);
    }
  }, [canSort, canColumnActions, headerCell, rowDensity]);

  const handleCellMouseLeave = useCallback(
    (event: ReactMouseEvent<HTMLDivElement, MouseEvent>): void => {
      if (!headerCell) {
        return;
      }

      // When the column actions menu is opened on right-click, its trigger button is portalled
      // into the document.body which fires mouseleave on the header cell with relatedTarget pointing
      // at that button. Since the floating menu lives outside the header cell's subtree, we need
      // to detect it via relatedTarget and keep the hovered state.
      if (
        event.relatedTarget instanceof HTMLElement &&
        event.relatedTarget.getAttribute('data-trigger') === 'context-action'
      ) {
        return;
      }

      const columnActionsMenu = headerCell.querySelector(
        '[data-trigger="useraction"]',
      );
      const isOpen = columnActionsMenu?.getAttribute('data-state') === 'open';
      if (isOpen) {
        // keep the hovered state while the column actions menu is open
        return;
      }

      isHoveredRef.current = false;
      // remove the hovered and narrow state
      headerCell.classList.remove(
        headerCellStyles.hovered,
        headerCellStyles.narrow,
      );
    },
    [headerCell],
  );

  const handleCellClick = useCallback(
    (event: ReactMouseEvent<HTMLDivElement, MouseEvent>): void => {
      const { target } = event;

      if (!(target instanceof HTMLElement) && !(target instanceof SVGElement)) {
        return;
      }

      if ('headerRow' in target.dataset) {
        getToggleSortingHandler?.()?.(event);
        return;
      }

      const columnHeader = target.closest('[role="columnheader"]');
      if (!columnHeader) {
        return;
      }

      let currentElement: typeof target | null = target;
      while (currentElement && currentElement !== columnHeader) {
        if (isInteractiveElement(currentElement)) {
          return;
        }
        currentElement = currentElement.parentElement;
      }

      getToggleSortingHandler?.()?.(event);
    },
    [getToggleSortingHandler],
  );

  return {
    handleCellActionsClose,
    handleCellMouseEnter,
    handleCellMouseLeave,
    handleCellClick,
  };
}
